anon: always drop the marker; for file: only\n\t\t * drop the marker if explicitly requested.\n\t\t */\n\t\tif (!vma_is_anonymous(vma) && !zap_drop_markers(details))\n\t\t\treturn 1;\n\t} else if (softleaf_is_guard_marker(entry)) {\n\t\t/*\n\t\t * Ordinary zapping should not remove guard PTE\n\t\t * markers. Only do so if we should remove PTE markers\n\t\t * in general.\n\t\t */\n\t\tif (!zap_drop_markers(details))\n\t\t\treturn 1;\n\t} else if (softleaf_is_hwpoison(entry) ||\n\t\t   softleaf_is_poison_marker(entry)) {\n\t\tif (!should_zap_cows(details))\n\t\t\treturn 1;\n\t} else {\n\t\t/* We should have covered all the swap entry types */\n\t\tpr_alert(\"unrecognized swap entry 0x%lx\\n\", entry.val);\n\t\tWARN_ON_ONCE(1);\n\t}\n\tclear_not_present_full_ptes(vma->vm_mm, addr, pte, nr, tlb->fullmm);\n\t*any_skipped = zap_install_uffd_wp_if_needed(vma, addr, pte, nr, details, ptent);\n\n\treturn nr;\n}\n\nstatic inline int do_zap_pte_range(struct mmu_gather *tlb,\n\t\t\t\t   struct vm_area_struct *vma, pte_t *pte,\n\t\t\t\t   unsigned long addr, unsigned long end,\n\t\t\t\t   struct zap_details *details, int *rss,\n\t\t\t\t   bool *force_flush, bool *force_break,\n\t\t\t\t   bool *any_skipped)\n{\n\tpte_t ptent = ptep_get(pte);\n\tint max_nr = (end - addr) / PAGE_SIZE;\n\tint nr = 0;\n\n\t/* Skip all consecutive none ptes */\n\tif (pte_none(ptent)) {\n\t\tfor (nr = 1; nr < max_nr; nr++) {\n\t\t\tptent = ptep_get(pte + nr);\n\t\t\tif (!pte_none(ptent))\n\t\t\t\tbreak;\n\t\t}\n\t\tmax_nr -= nr;\n\t\tif (!max_nr)\n\t\t\treturn nr;\n\t\tpte += nr;\n\t\taddr += nr * PAGE_SIZE;\n\t}\n\n\tif (pte_present(ptent))\n\t\tnr += zap_present_ptes(tlb, vma, pte, ptent, max_nr, addr,\n\t\t\t\t       details, rss, force_flush, force_break,\n\t\t\t\t       any_skipped);\n\telse\n\t\tnr += zap_nonpresent_ptes(tlb, vma, pte, ptent, max_nr, addr,\n\t\t\t\t\t  details, rss, any_skipped);\n\n\treturn nr;\n}\n\nstatic unsigned long zap_pte_range(struct mmu_gather *tlb,\n\t\t\t\tstruct vm_area_struct *vma, pmd_t *pmd,\n\t\t\t\tunsigned long addr, unsigned long end,\n\t\t\t\tstruct zap_details *details)\n{\n\tbool force_flush = false, force_break = false;\n\tstruct mm_struct *mm = tlb->mm;\n\tint rss[NR_MM_COUNTERS];\n\tspinlock_t *ptl;\n\tpte_t *start_pte;\n\tpte_t *pte;\n\tpmd_t pmdval;\n\tunsigned long start = addr;\n\tbool can_reclaim_pt = reclaim_pt_is_enabled(start, end, details);\n\tbool direct_reclaim = true;\n\tint nr;\n\nretry:\n\ttlb_change_page_size(tlb, PAGE_SIZE);\n\tinit_rss_vec(rss);\n\tstart_pte = pte = pte_offset_map_lock(mm, pmd, addr, &ptl);\n\tif (!pte)\n\t\treturn addr;\n\n\tflush_tlb_batched_pending(mm);\n\tarch_enter_lazy_mmu_mode();\n\tdo {\n\t\tbool any_skipped = false;\n\n\t\tif (need_resched()) {\n\t\t\tdirect_reclaim = false;\n\t\t\tbreak;\n\t\t}\n\n\t\tnr = do_zap_pte_range(tlb, vma, pte, addr, end, details, rss,\n\t\t\t\t      &force_flush, &force_break, &any_skipped);\n\t\tif (any_skipped)\n\t\t\tcan_reclaim_pt = false;\n\t\tif (unlikely(force_break)) {\n\t\t\taddr += nr * PAGE_SIZE;\n\t\t\tdirect_reclaim = false;\n\t\t\tbreak;\n\t\t}\n\t} while (pte += nr, addr += PAGE_SIZE * nr, addr != end);\n\n\t/*\n\t * Fast path: try to hold the pmd lock and unmap the PTE page.\n\t *\n\t * If the pte lock was released midway (retry case), or if the attempt\n\t * to hold the pmd lock failed, then we need to recheck all pte entries\n\t * to ensure they are still none, thereby preventing the pte entries\n\t * from being repopulated by another thread.\n\t */\n\tif (can_reclaim_pt && direct_reclaim && addr == end)\n\t\tdirect_reclaim = try_get_and_clear_pmd(mm, pmd, &pmdval);\n\n\tadd_mm_rss_vec(mm, rss);\n\tarch_leave_lazy_mmu_mode();\n\n\t/* Do the actual TLB flush before dropping ptl */\n\tif (force_flush) {\n\t\ttlb_flush_mmu_tlbonly(tlb);\n\t\ttlb_flush_rmaps(tlb, vma);\n\t}\n\tpte_unmap_unlock(start_pte, ptl);\n\n\t/*\n\t * If we forced a TLB flush (either due to running out of\n\t * batch buffers or because we needed to flush dirty TLB\n\t * entries before releasing the ptl), free the batched\n\t * memory too. Come back again if we didn't do everything.\n\t */\n\tif (force_flush)\n\t\ttlb_flush_mmu(tlb);\n\n\tif (addr != end) {\n\t\tcond_resched();\n\t\tforce_flush = false;\n\t\tforce_break = false;\n\t\tgoto retry;\n\t}\n\n\tif (can_reclaim_pt) {\n\t\tif (direct_reclaim)\n\t\t\tfree_pte(mm, start, tlb, pmdval);\n\t\telse\n\t\t\ttry_to_free_pte(mm, pmd, start, tlb);\n\t}\n\n\treturn addr;\n}\n\nstatic inline unsigned long zap_pmd_range(struct mmu_gather *tlb,\n\t\t\t\tstruct vm_area_struct *vma, pud_t *pud,\n\t\t\t\tunsigned long addr, unsigned long end,\n\t\t\t\tstruct zap_details *details)\n{\n\tpmd_t *pmd;\n\tunsigned long next;\n\n\tpmd = pmd_offset(pud, addr);\n\tdo {\n\t\tnext = pmd_addr_end(addr, end);\n\t\tif (pmd_is_huge(*pmd)) {\n\t\t\tif (next - addr != HPAGE_PMD_SIZE)\n\t\t\t\t__split_huge_pmd(vma, pmd, addr, false);\n\t\t\telse if (zap_huge_pmd(tlb, vma, pmd, addr)) {\n\t\t\t\taddr = next;\n\t\t\t\tcontinue;\n\t\t\t}\n\t\t\t/* fall through */\n\t\t} else if (details && details->single_folio &&\n\t\t\t   folio_test_pmd_mappable(details->single_folio) &&\n\t\t\t   next - addr == HPAGE_PMD_SIZE && pmd_none(*pmd)) {\n\t\t\tspinlock_t *ptl = pmd_lock(tlb->mm, pmd);\n\t\t\t/*\n\t\t\t * Take and drop THP pmd lock so that we cannot return\n\t\t\t * prematurely, while zap_huge_pmd() has cleared *pmd,\n\t\t\t * but not yet decremented compound_mapcount().\n\t\t\t */\n\t\t\tspin_unlock(ptl);\n\t\t}\n\t\tif (pmd_none(*pmd)) {\n\t\t\taddr = next;\n\t\t\tcontinue;\n\t\t}\n\t\taddr = zap_pte_range(tlb, vma, pmd, addr, next, details);\n\t\tif (addr != next)\n\t\t\tpmd--;\n\t} while (pmd++, cond_resched(), addr != end);\n\n\treturn addr;\n}\n\nstatic inline unsigned long zap_pud_range(struct mmu_gather *tlb,\n\t\t\t\tstruct vm_area_struct *vma, p4d_t *p4d,\n\t\t\t\tunsigned long addr, unsigned long end,\n\t\t\t\tstruct zap_details *details)\n{\n\tpud_t *pud;\n\tunsigned long next;\n\n\tpud = pud_offset(p4d, addr);\n\tdo {\n\t\tnext = pud_addr_end(addr, end);\n\t\tif (pud_trans_huge(*pud)) {\n\t\t\tif (next - addr != HPAGE_PUD_SIZE)\n\t\t\t\tsplit_huge_pud(vma, pud, addr);\n\t\t\telse if (zap_huge_pud(tlb, vma, pud, addr))\n\t\t\t\tgoto next;\n\t\t\t/* fall through */\n\t\t}\n\t\tif (pud_none_or_clear_bad(pud))\n\t\t\tcontinue;\n\t\tnext = zap_pmd_range(tlb, vma, pud, addr, next, details);\nnext:\n\t\tcond_resched();\n\t} while (pud++, addr = next, addr != end);\n\n\treturn addr;\n}\n\nstatic inline unsigned long zap_p4d_range(struct mmu_gather *tlb,\n\t\t\t\tstruct vm_area_struct *vma, pgd_t *pgd,\n\t\t\t\tunsigned long addr, unsigned long end,\n\t\t\t\tstruct zap_details *details)\n{\n\tp4d_t *p4d;\n\tunsigned long next;\n\n\tp4d = p4d_offset(pgd, addr);\n\tdo {\n\t\tnext = p4d_addr_end(addr, end);\n\t\tif (p4d_none_or_clear_bad(p4d))\n\t\t\tcontinue;\n\t\tnext = zap_pud_range(tlb, vma, p4d, addr, next, details);\n\t} while (p4d++, addr = next, addr != end);\n\n\treturn addr;\n}\n\nvoid unmap_page_range(struct mmu_gather *tlb,\n\t\t\t     struct vm_area_struct *vma,\n\t\t\t     unsigned long addr, unsigned long end,\n\t\t\t     struct zap_details *details)\n{\n\tpgd_t *pgd;\n\tunsigned long next;\n\n\tBUG_ON(addr >= end);\n\ttlb_start_vma(tlb, vma);\n\tpgd = pgd_offset(vma->vm_mm, addr);\n\tdo {\n\t\tnext = pgd_addr_end(addr, end);\n\t\tif (pgd_none_or_clear_bad(pgd))\n\t\t\tcontinue;\n\t\tnext = zap_p4d_range(tlb, vma, pgd, addr, next, details);\n\t} while (pgd++, addr = next, addr != end);\n\ttlb_end_vma(tlb, vma);\n}\n\n\nstatic void unmap_single_vma(struct mmu_gather *tlb,\n\t\tstruct vm_area_struct *vma, unsigned long start_addr,\n\t\tunsigned long end_addr, struct zap_details *details)\n{\n\tunsigned long start = max(vma->vm_start, start_addr);\n\tunsigned long end;\n\n\tif (start >= vma->vm_end)\n\t\treturn;\n\tend = min(vma->vm_end, end_addr);\n\tif (end <= vma->vm_start)\n\t\treturn;\n\n\tif (vma->vm_file)\n\t\tuprobe_munmap(vma, start, end);\n\n\tif (start != end) {\n\t\tif (unlikely(is_vm_hugetlb_page(vma))) {\n\t\t\t/*\n\t\t\t * It is undesirable to test vma->vm_file as it\n\t\t\t * should be non-null for valid hugetlb area.\n\t\t\t * However, vm_file will be NULL in the error\n\t\t\t * cleanup path of mmap_region. When\n\t\t\t * hugetlbfs ->mmap method fails,\n\t\t\t * mmap_region() nullifies vma->vm_file\n\t\t\t * before calling this function to clean up.\n\t\t\t * Since no pte has actually been setup, it is\n\t\t\t * safe to do nothing in this case.\n\t\t\t */\n\t\t\tif (vma->vm_file) {\n\t\t\t\tzap_flags_t zap_flags = details ?\n\t\t\t\t    details->zap_flags : 0;\n\t\t\t\t__unmap_hugepage_range(tlb, vma, start, end,\n\t\t\t\t\t\t\t     NULL, zap_flags);\n\t\t\t}\n\t\t} else\n\t\t\tunmap_page_range(tlb, vma, start, end, details);\n\t}\n}\n\n/**\n * unmap_vmas - unmap a range of memory covered by a list of vma's\n * @tlb: address of the caller's struct mmu_gather\n * @mas: the maple state\n * @vma: the starting vma\n * @start_addr: virtual address at which to start unmapping\n * @end_addr: virtual address at which to end unmapping\n * @tree_end: The maximum index to check\n *\n * Unmap all pages in the vma list.\n *\n * Only addresses between `start' and `end' will be unmapped.\n *\n * The VMA list must be sorted in ascending virtual address order.\n *\n * unmap_vmas() assumes that the caller will flush the whole unmapped address\n * range after unmap_vmas() returns.  So the only responsibility here is to\n * ensure that any thus-far unmapped pages are flushed before unmap_vmas()\n * drops the lock and schedules.\n */\nvoid unmap_vmas(struct mmu_gather *tlb, struct ma_state *mas,\n\t\tstruct vm_area_struct *vma, unsigned long start_addr,\n\t\tunsigned long end_addr, unsigned long tree_end)\n{\n\tstruct mmu_notifier_range range;\n\tstruct zap_details details = {\n\t\t.zap_flags = ZAP_FLAG_DROP_MARKER | ZAP_FLAG_UNMAP,\n\t\t/* Careful - we need to zap private pages too! */\n\t\t.even_cows = true,\n\t};\n\n\tmmu_notifier_range_init(&range, MMU_NOTIFY_UNMAP, 0, vma->vm_mm,\n\t\t\t\tstart_addr, end_addr);\n\tmmu_notifier_invalidate_range_start(&range);\n\tdo {\n\t\tunsigned long start = start_addr;\n\t\tunsigned long end = end_addr;\n\t\thugetlb_zap_begin(vma, &start, &end);\n\n... [Diff truncated. Dropped 4940 lines] ...\n\n */\nint access_process_vm(struct task_struct *tsk, unsigned long addr,\n\t\tvoid *buf, int len, unsigned int gup_flags)\n{\n\tstruct mm_struct *mm;\n\tint ret;\n\n\tmm = get_task_mm(tsk);\n\tif (!mm)\n\t\treturn 0;\n\n\tret = __access_remote_vm(mm, addr, buf, len, gup_flags);\n\n\tmmput(mm);\n\n\treturn ret;\n}\nEXPORT_SYMBOL_GPL(access_process_vm);\n\n#ifdef CONFIG_BPF_SYSCALL\n/*\n * Copy a string from another process's address space as given in mm.\n * If there is any error return -EFAULT.\n */\nstatic int __copy_remote_vm_str(struct mm_struct *mm, unsigned long addr,\n\t\t\t\tvoid *buf, int len, unsigned int gup_flags)\n{\n\tvoid *old_buf = buf;\n\tint err = 0;\n\n\t*(char *)buf = '\\0';\n\n\tif (mmap_read_lock_killable(mm))\n\t\treturn -EFAULT;\n\n\taddr = untagged_addr_remote(mm, addr);\n\n\t/* Avoid triggering the temporary warning in __get_user_pages */\n\tif (!vma_lookup(mm, addr)) {\n\t\terr = -EFAULT;\n\t\tgoto out;\n\t}\n\n\twhile (len) {\n\t\tint bytes, offset, retval;\n\t\tvoid *maddr;\n\t\tstruct folio *folio;\n\t\tstruct page *page;\n\t\tstruct vm_area_struct *vma = NULL;\n\n\t\tpage = get_user_page_vma_remote(mm, addr, gup_flags, &vma);\n\t\tif (IS_ERR(page)) {\n\t\t\t/*\n\t\t\t * Treat as a total failure for now until we decide how\n\t\t\t * to handle the CONFIG_HAVE_IOREMAP_PROT case and\n\t\t\t * stack expansion.\n\t\t\t */\n\t\t\t*(char *)buf = '\\0';\n\t\t\terr = -EFAULT;\n\t\t\tgoto out;\n\t\t}\n\n\t\tfolio = page_folio(page);\n\t\tbytes = len;\n\t\toffset = addr & (PAGE_SIZE - 1);\n\t\tif (bytes > PAGE_SIZE - offset)\n\t\t\tbytes = PAGE_SIZE - offset;\n\n\t\tmaddr = kmap_local_folio(folio, folio_page_idx(folio, page) * P